 1	import React, { FC, useMemo, useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { VirtualMachineModelRef } from '@kubevirt-ui/kubevirt-api/console';
 5	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
 9	import { SelectOption, Title } from '@patternfly/react-core';
10	
11	import { ALL_NETWORKS } from '../utils/constants';
12	
13	import useQuery from './hook/useQuery';
14	import NetworkChartsByNIC from './NetworkChartsByNIC';
15	
16	import '../virtual-machine-metrics-tab.scss';
17	
18	type NetworkChartsProps = {
19	  vmi: V1VirtualMachineInstance;
20	};
21	
22	const NetworkCharts: FC<NetworkChartsProps> = ({ vmi }) => {
23	  const { t } = useKubevirtTranslation();
24	  const navigate = useNavigate();
25	
26	  const interfacesNames = useMemo(() => {
27	    const interfaces = vmi?.spec?.domain?.devices?.interfaces?.map((nic) => nic?.name);
28	    interfaces?.unshift(ALL_NETWORKS);
29	    return interfaces;
30	  }, [vmi]);
31	
32	  const query = useQuery();
33	  const [selectedNetwork, setSelectedNetwork] = useState<string>(
34	    query?.get('network') || ALL_NETWORKS,
35	  );
36	
37	  return (
38	    <div>
39	      <Title className="networkcharts-by-nic--title" headingLevel="h4">
40	        {t('Network interface:')}
41	      </Title>{' '}
42	      <FormPFSelect
43	        onSelect={(_, network: string) => setSelectedNetwork(network)}
44	        selected={selectedNetwork}
45	        toggleProps={{ className: 'network ul.pf-v5-c-dropdown__menu' }}
46	      >
47	        {interfacesNames?.map((nic) => (
48	          <SelectOption
49	            onClick={() => {
50	              navigate(
51	                `/k8s/ns/${getNamespace(vmi)}/${VirtualMachineModelRef}/${getName(
52	                  vmi,
53	                )}/metrics?network=${nic}`,
54	              );
55	            }}
56	            key={nic}
57	            value={nic}
58	          >
59	            {nic}
60	          </SelectOption>
61	        ))}
62	      </FormPFSelect>
63	      <NetworkChartsByNIC nic={selectedNetwork} vmi={vmi} />
64	    </div>
65	  );
66	};
67	
68	export default NetworkCharts;

